And if we look at the effect of body mass on bill length, we can see another very clear effect.



::: {.cell layout-align="center" renderings='["light","dark"]'}

```{.r .cell-code  code-fold="true" code-summary="Plotting code"}
penguins |> 
  ggplot(
    aes(body_mass, bill_len, color = species)
  ) + 
    geom_point() +
    guides(
      color = "none"
    )-> p

p + 
 stat_ellipse(
  geom = "labelpath",
  aes(label = species),
  hjust = 0,
  label.padding = 0.01,
  show.legend = F  
) 

p  + 
 stat_ellipse(
  geom = "labelpath",
  aes(label = species),
  hjust = 0,
  label.padding = 0.01,
  fill = plot_bg,
  show.legend = F
) + 
  theme_darkmode()
```

::: {.cell-output-display}
![](index_files/figure-html/unnamed-chunk-6-1.png){fig-align='center' width=480}
:::

::: {.cell-output-display}
![](index_files/figure-html/unnamed-chunk-6-2.png){fig-align='center' width=480}
:::
:::


Let's, really quick, get the mean and standard error of bill length by species.


::: {.cell}

```{.r .cell-code}
penguins |>
  drop_na(starts_with("bill_")) ->
  penguin_full

penguin_full|>
  summarise(
    .by = species,
    estimate = mean(bill_len),
    sd = sd(bill_len),
    n = n()
  ) |> 
  mutate(
    se = sd / (sqrt(n)),
    conf.low = estimate - (1.96*se),
    conf.high = estimate + (1.96*se),
    method = "mean"
  ) ->
  mean_est
```
:::



::: {.cell}

```{.r .cell-code  code-fold="true" code-summary="table_code"}
mean_est |>
  select(species, estimate, conf.low, conf.high) |>
  tt()
```

