One way to estimate the effect of species on bill length would be to subtract these means from eachother.

$$
\begin{aligned}
\bar{Y}^c - \bar{Y}^a\\
\bar{Y}^g - \bar{Y}^a
\end{aligned}
$$


::: {.cell}

```{.r .cell-code  code-fold="true" code-summary="Table code"}
mean_est |>
  select(
    species,
    estimate
  ) |>
  pivot_wider(
    names_from = species,
    values_from = estimate
  ) |>
  mutate(
    Chinstrap - Adelie,
    Gentoo - Adelie
  )|>
  select(
    matches("-")
  ) |>
  pivot_longer(
    everything(),
    names_to = "contrast",
    values_to = "estimate"
  ) |>
  mutate(method = "mean") ->
  mean_comparisons

mean_comparisons |> 
  select(-method) |> 
  tt()
```

